t.script:

function IPOS_LOG() {
    var args = Array.prototype.slice.call(arguments);
    args.unshift('[RentalInvoicePay]');
    console.log.apply(console, args);
}
function IPOS_ERR() {
    var args = Array.prototype.slice.call(arguments);
    args.unshift('[RentalInvoicePay]');
    console.error.apply(console, args);
}

var selectedProviderId   = null;
var selectedProviderCode = null;
var ftdLoadPromise       = null;

// Payment option: 'full' or 'deposit'
var selectedPaymentOption = 'full';

function selectPaymentOption(option) {
    selectedPaymentOption = option;
    var fullEl    = document.getElementById('opt-full');
    var depositEl = document.getElementById('opt-deposit');
    var sym       = document.getElementById('hid-currency-symbol').value;
    var fullAmt   = parseFloat(document.getElementById('hid-amount').value);
    var depAmt    = parseFloat(document.getElementById('hid-deposit-amount').value);
    var btnLabel  = document.getElementById('pay-btn-amount');

    if (option === 'full') {
        fullEl.style.borderColor    = '#875A7B';
        fullEl.style.background     = '#fdf6ff';
        depositEl.style.borderColor = '#e0e0e0';
        depositEl.style.background  = 'white';
        if (btnLabel) btnLabel.textContent = sym + fullAmt.toFixed(2);
    } else {
        depositEl.style.borderColor = '#e65100';
        depositEl.style.background  = '#fff8f0';
        fullEl.style.borderColor    = '#e0e0e0';
        fullEl.style.background     = 'white';
        if (btnLabel) btnLabel.textContent = sym + depAmt.toFixed(2);
    }
    IPOS_LOG('selectPaymentOption', option);
}

function selectProvider(el) {
    // Reset all cards
    document.querySelectorAll('[data-provider-id]').forEach(function(e) {
        e.style.borderColor = '#e0e0e0';
        e.style.background  = 'white';
    });

    // Highlight selected
    el.style.borderColor = '#875A7B';
    el.style.background  = '#fdf6ff';

    selectedProviderId   = parseInt(el.getAttribute('data-provider-id'));
    selectedProviderCode = el.getAttribute('data-provider-code');
    IPOS_LOG('selectProvider', {
        selectedProviderId: selectedProviderId,
        selectedProviderCode: selectedProviderCode,
        elementId: el && el.id,
    });
    var iposContainer = document.getElementById('ipos-card-container');
    if (iposContainer) {
        iposContainer.style.display = 'block';
        IPOS_LOG('ipos-card-container visible', {
            display: iposContainer.style.display,
            existsCcNumber: !!document.getElementById('ccnumber'),
            existsCcExpiry: !!document.getElementById('ccexpiry'),
            existsCcCvv: !!document.getElementById('cccvv'),
        });
    }
}

// ── Card field formatting ─────────────────────────────────
function _formatCardNumber(input) {
    var digits = input.value.replace(/\D/g, '').substring(0, 16);
    var groups = [];
    for (var i = 0; i < digits.length; i += 4) {
        groups.push(digits.substring(i, i + 4));
    }
    input.value = groups.join(' ');
}

function _formatExpiry(input, e) {
    var val = input.value;
    // Backspace on "MM/" — strip the slash so the user can delete the month
    if (e && (e.key === 'Backspace' || e.inputType === 'deleteContentBackward')) {
        if (val.length === 3 && val[2] === '/') {
            input.value = val.substring(0, 2);
            return;
        }
    }
    var raw = val.replace(/\D/g, '').substring(0, 4);
    if (raw.length >= 3) {
        input.value = raw.substring(0, 2) + '/' + raw.substring(2, 4);
    } else if (raw.length === 2 && !(e && (e.key === 'Backspace' || e.inputType === 'deleteContentBackward'))) {
        input.value = raw + '/';
    } else {
        input.value = raw;
    }
}

function _digitsOnly(input, max) {
    input.value = input.value.replace(/\D/g, '').substring(0, max);
}

function _wireCardFormatting() {
    var ccn = document.getElementById('ccnumber');
    var cce = document.getElementById('ccexpiry');
    var ccv = document.getElementById('cccvv');
    if (ccn && !ccn._formatted) {
        ccn._formatted = true;
        ccn.addEventListener('input', function() { _formatCardNumber(ccn); });
        ccn.addEventListener('paste', function() { setTimeout(function() { _formatCardNumber(ccn); }, 0); });
    }
    if (cce && !cce._formatted) {
        cce._formatted = true;
        cce.addEventListener('input', function(e) { _formatExpiry(cce, e); });
        cce.addEventListener('keydown', function(e) {
            if (e.key === 'Backspace') { setTimeout(function() { _formatExpiry(cce, e); }, 0); }
        });
    }
    if (ccv && !ccv._formatted) {
        ccv._formatted = true;
        ccv.addEventListener('input', function() { _digitsOnly(ccv, 4); });
    }
}

document.addEventListener('DOMContentLoaded', _wireCardFormatting);
_wireCardFormatting();
// ─────────────────────────────────────────────────────────────

async function _rpcJson(url, params) {
    IPOS_LOG('RPC request', { url: url, params: params });
    var response = await fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ jsonrpc: '2.0', method: 'call', id: Date.now(), params: params || {} })
    });
    var data = await response.json();
    IPOS_LOG('RPC response', { url: url, ok: response.ok, data: data });
    if (data.error) throw new Error(data.error.data && data.error.data.message ? data.error.data.message : data.error.message);
    return data.result;
}

async function _ensureFtdLoaded(providerId) {
    var cfg = await _rpcJson('/payment/ipos_pay/get_config', { provider_id: providerId });
    IPOS_LOG('FTD config', cfg);
    if (!cfg || !cfg.data_token || !cfg.data_src) {
        throw new Error('IPOS configuration missing.');
    }
    var ftdSrc = cfg.ftd_src || (cfg.data_src + '/ftd/v1/freedomtodesign.js');

    var script = document.getElementById('ftd');
    if (!script) {
        IPOS_LOG('Creating #ftd script');
        script = document.createElement('script');
        script.id = 'ftd';
        script.async = false;
        script.setAttribute('security_key', cfg.data_token);
        script.setAttribute('data-src', cfg.data_src);
        script.src = ftdSrc;
        ftdLoadPromise = new Promise(function(resolve, reject) {
            script.addEventListener('load', function() { resolve(); }, { once: true });
            script.addEventListener('error', function() { reject(new Error('Failed to load FTD script.')); }, { once: true });
        });
        document.head.appendChild(script);
        await ftdLoadPromise;
        IPOS_LOG('#ftd loaded');
    } else {
        IPOS_LOG('Reusing #ftd script');
        script.setAttribute('security_key', cfg.data_token);
        script.setAttribute('data-src', cfg.data_src);
        if (!script.getAttribute('src')) script.setAttribute('src', ftdSrc);
    }

    var alias = document.getElementById('myScript');
    if (!alias) {
        IPOS_LOG('Creating #myScript alias');
        alias = document.createElement('script');
        alias.id = 'myScript';
        alias.type = 'text/plain';
        document.head.appendChild(alias);
    }
    alias.setAttribute('security_key', cfg.data_token);
    alias.setAttribute('data-src', cfg.data_src);
    alias.setAttribute('src', ftdSrc);

    if (typeof window.postData !== 'function') {
        throw new Error('FTD script loaded but postData() not available.');
    }
    IPOS_LOG('FTD ready', { hasPostData: typeof window.postData === 'function' });
}

async function _generateFtdToken(providerId) {
    await _ensureFtdLoaded(providerId);
    IPOS_LOG('Calling postData()');
    var tokenData = await new Promise(function(resolve, reject) {
        try {
            var ret = window.postData(function(data) { resolve(data); });
            if (ret && typeof ret.then === 'function') ret.then(resolve, reject);
        } catch (err) {
            reject(err);
        }
    });
    var token = (tokenData && (tokenData.payment_token_id || tokenData.paymentTokenId || tokenData.payment_token || tokenData.token)) || '';
    if (!token) throw new Error('FTD did not return payment token.');
    IPOS_LOG('FTD token generated', { tokenLength: token.length });
    return token;
}

async function submitPayment() {
    IPOS_LOG('submitPayment clicked', {
        selectedProviderId: selectedProviderId,
        selectedProviderCode: selectedProviderCode,
        selectedPaymentOption: selectedPaymentOption,
    });
    if (!selectedProviderId || selectedProviderCode !== 'ipos_pay') {
        alert('Please select IPOS Pay.');
        return;
    }

    var btn = document.getElementById('pay-btn');
    btn.disabled = true;
    var origLabel = btn.innerHTML;
    btn.textContent = 'Processing...';
    document.getElementById('ipos-card-errors').textContent = '';

    var invoiceId   = parseInt(document.getElementById('hid-invoice-id').value);
    var accessToken = document.getElementById('hid-access-token').value;
    var fullAmt     = parseFloat(document.getElementById('hid-amount').value);
    var depAmt      = parseFloat(document.getElementById('hid-deposit-amount').value);
    var paymentAmount = selectedPaymentOption === 'deposit' ? depAmt : fullAmt;

    try {
        // 1) Create Odoo payment.transaction
        var result = await _rpcJson('/rental/pay/create-transaction', {
            invoice_id: invoiceId,
            access_token: accessToken,
            provider_id: selectedProviderId,
            payment_amount: paymentAmount,
        });
        if (!result || result.error) {
            throw new Error(result && result.error ? result.error : 'Transaction creation failed');
        }
        if (!result.reference) {
            throw new Error('Transaction reference missing.');
        }

        // 2) Generate FTD payment token from card fields
        var paymentTokenId = await _generateFtdToken(selectedProviderId);

        // 3) Charge via IPOS transact
        var charge = await _rpcJson('/payment/ipos_pay/charge_token', {
            reference: result.reference,
            payment_token_id: paymentTokenId,
        });
        IPOS_LOG('charge response', charge);
        if (!charge || charge.state !== 'done') {
            throw new Error((charge && charge.message) || 'IPOS charge failed.');
        }

        // 4) Go to payment status page
        window.location.href = '/rental/pay/status?tx_id=' + result.tx_id + '&access_token=' + accessToken;
    } catch(e) {
        IPOS_ERR('submitPayment failed', e);
        document.getElementById('ipos-card-errors').textContent = e.message || 'Payment failed.';
        alert('Payment error: ' + (e.message || 'Unknown error'));
        btn.disabled   = false;
        btn.innerHTML  = origLabel;
    }
}

// Auto-select first provider and default payment option on load.
document.addEventListener('DOMContentLoaded', function () {
    IPOS_LOG('DOMContentLoaded', {
        providerCount: document.querySelectorAll('[data-provider-id]').length,
    });
    var firstProvider = document.querySelector('[data-provider-id]');
    if (firstProvider) {
        IPOS_LOG('Auto-selecting provider', { id: firstProvider.id });
        selectProvider(firstProvider);
    } else {
        IPOS_ERR('No provider elements found on page');
    }
    // Default to "Pay in Full"
    selectPaymentOption('full');
});

