max-width:500px; margin:0 auto; background:white;
                            border-radius:8px; padding:48px 40px; text-align:center;
                            border:1px solid #e0e0e0; box-shadow:0 2px 12px rgba(0,0,0,0.06);

t.script:
(function () {
    var cb     = document.getElementById('agree_cb');
    var wrap   = document.getElementById('agree_wrap');
    var btnPay = document.getElementById('btn_pay');
    var btnDep = document.getElementById('btn_deposit');
    if (!cb) return;

    function sync() {
        var ok = cb.checked;
        if (wrap) wrap.classList.toggle('checked', ok);
        [btnPay, btnDep].forEach(function (btn) {
            if (btn) btn.classList.toggle('active', ok);
        });
    }

    cb.addEventListener('change', sync);
    sync();
})();

